package ru.kryuch.krtg.searcher.controller;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.validation.BindingResult;import org.springframework.web.bind.annotation.GetMapping;import org.springframework.web.bind.annotation.ModelAttribute;import org.springframework.web.bind.annotation.PostMapping;import org.springframework.web.bind.annotation.RequestMapping;import ru.kryuch.krtg.searcher.dto.SettingsWrapper;import ru.kryuch.krtg.searcher.service.SettingService;import ru.kryuch.krtg.searcher.service.VacancyService;@Controller@RequiredArgsConstructor@RequestMapping("/settings")public class SettingsController {	private final SettingService settingService;	@GetMapping("/")	public String index(Model model) {		model.addAttribute("items", new SettingsWrapper(settingService.getAll()));		model.addAttribute("page", "settings");		return "index";	}	@PostMapping(value = "/save")	public String save(@ModelAttribute SettingsWrapper values, BindingResult result, Model model) {		settingService.save(values);		return "redirect:/settings/";	}}